// Validates payload, allocates MOP ID (fs mutex), renders HTML, emits
// binary {html, css} for the HTTP Request node.

const fs = require('fs');

const MOP_DIR       = '/data/mop';
const INDEX_DIR     = MOP_DIR + '/index';
const PDF_DIR       = MOP_DIR + '/pdf';
const PENDING_DIR   = INDEX_DIR + '/.pending';
const CSV_PATH      = INDEX_DIR + '/mops-index.csv';
const TEMPLATE_HTML = MOP_DIR + '/templates/mop.html';
const TEMPLATE_CSS  = MOP_DIR + '/templates/mop.css';

function ensureDirs() {
  fs.mkdirSync(INDEX_DIR,   { recursive: true });
  fs.mkdirSync(PDF_DIR,     { recursive: true });
  fs.mkdirSync(PENDING_DIR, { recursive: true });
  if (!fs.existsSync(CSV_PATH)) {
    fs.writeFileSync(CSV_PATH, '\uFEFFid;title;keywords;severity;perimeter;filename;sub_procs;created_at\n');
  }
}

function allocateId(payloadStr) {
  const year = new Date().getUTCFullYear();
  ensureDirs();
  const re = new RegExp('^MOP-' + year + '-(\\d+)');
  let max = 0;
  const csv = fs.readFileSync(CSV_PATH, 'utf8');
  for (const line of csv.split('\n').slice(1)) {
    const m = line.match(re);
    if (m) max = Math.max(max, parseInt(m[1], 10));
  }
  for (const f of fs.readdirSync(PENDING_DIR)) {
    const m = f.match(new RegExp('^MOP-' + year + '-(\\d+)$'));
    if (m) max = Math.max(max, parseInt(m[1], 10));
  }
  let next = max + 1;
  while (next < max + 1000) {
    const id = 'MOP-' + year + '-' + String(next).padStart(4, '0');
    try {
      fs.writeFileSync(PENDING_DIR + '/' + id, payloadStr, { flag: 'wx' });
      return id;
    } catch (e) {
      if (e.code !== 'EEXIST') throw e;
      next++;
    }
  }
  throw new Error('allocate: exhausted retries');
}

// Mini Jinja-subset renderer ({{var}}, {{var|upper}}, {% for %}, {% if %})
function getPath(obj, p) {
  return p.split('.').reduce((o, k) => (o == null ? o : o[k]), obj);
}
function escHtml(s) {
  return String(s == null ? '' : s)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
}
function renderTpl(tpl, ctx) {
  tpl = tpl.replace(
    /\{%\s*for\s+(\w+)\s+in\s+([\w.]+)\s*%\}([\s\S]*?)\{%\s*endfor\s*%\}/g,
    (_, varName, arrPath, body) => {
      const arr = getPath(ctx, arrPath);
      if (!Array.isArray(arr)) return '';
      return arr.map(item => renderTpl(body, { ...ctx, [varName]: item })).join('');
    }
  );
  tpl = tpl.replace(
    /\{%\s*if\s+([\w.]+)\s*%\}([\s\S]*?)\{%\s*endif\s*%\}/g,
    (_, expr, body) => {
      const v = getPath(ctx, expr);
      return (v && (!Array.isArray(v) || v.length > 0)) ? body : '';
    }
  );
  tpl = tpl.replace(
    /\{\{\s*([\w.]+)(?:\s*\|\s*(\w+))?\s*\}\}/g,
    (_, p, filter) => {
      let v = getPath(ctx, p);
      if (v == null) return '';
      if (filter === 'upper') v = String(v).toUpperCase();
      return escHtml(v);
    }
  );
  return tpl;
}

// ─── main ─────────────────────────────────────────────────────────────
const input = $input.first().json;
const payload = input.body || input;

const required = ['title', 'severity', 'perimeter', 'incident', 'steps'];
for (const k of required) {
  if (payload[k] == null) {
    // Validation error — short-circuit with statusCode 400
    return [{ json: { ok: false, error: 'missing field: ' + k, statusCode: 400, _shortCircuit: true } }];
  }
}

ensureDirs();
const id = allocateId(JSON.stringify(payload));
const ctx = { ...payload, id };

const tpl  = fs.readFileSync(TEMPLATE_HTML, 'utf8');
const html = renderTpl(tpl, ctx);
const css  = fs.readFileSync(TEMPLATE_CSS, 'utf8');

// Emit binary fields for HTTP Request node (multipart file upload)
return [{
  json: {
    id,
    payload,
    filename: id + '.pdf',
    sub_procs: (payload.steps || [])
      .map(s => s.link_sp)
      .filter(Boolean)
      .join(','),
  },
  binary: {
    html: {
      data: Buffer.from(html, 'utf8').toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html',
      fileExtension: 'html',
    },
    css: {
      data: Buffer.from(css, 'utf8').toString('base64'),
      mimeType: 'text/css',
      fileName: 'mop.css',
      fileExtension: 'css',
    },
  },
}];

// Writes binary PDF to /data/mop/pdf/<id>.pdf, appends CSV row,
// removes pending marker. Returns success JSON for Respond node.

const fs = require('fs');

const MOP_DIR     = '/data/mop';
const INDEX_DIR   = MOP_DIR + '/index';
const PDF_DIR     = MOP_DIR + '/pdf';
const PENDING_DIR = INDEX_DIR + '/.pending';
const CSV_PATH    = INDEX_DIR + '/mops-index.csv';
const PUBLIC_BASE = process.env.MOP_PUBLIC_BASE || 'https://mop-dl.ewutelo.cloud';

const item = $input.first();
const j = item.json;
const id = j.id;
const filename = j.filename;
const payload = j.payload || {};

// Read binary PDF via n8n helper API. Binary data may live in memory OR on
// disk (filesystem-v2 mode) — helpers.getBinaryDataBuffer abstracts both.
// Ref: https://docs.n8n.io/code/builtin/data/#binary-helpers
const pdfBuf = await this.helpers.getBinaryDataBuffer(0, 'pdf');
if (!Buffer.isBuffer(pdfBuf) || pdfBuf.length === 0) {
  throw new Error('persist: empty binary.pdf from HTTP Request node');
}

const pdfPath = PDF_DIR + '/' + filename;
fs.writeFileSync(pdfPath, pdfBuf);

// Append CSV row
const csvLine = [
  id,
  '"' + String(payload.title || '').replace(/"/g, '""') + '"',
  '"' + (Array.isArray(payload.keywords) ? payload.keywords.join(',') : (payload.keywords || '')) + '"',
  payload.severity || 'minor',
  payload.perimeter || '',
  filename,
  j.sub_procs || '',
  new Date().toISOString(),
].join(';') + '\n';
fs.appendFileSync(CSV_PATH, csvLine);

// Remove pending marker
try { fs.unlinkSync(PENDING_DIR + '/' + id); } catch (_) {}

return [{
  json: {
    ok: true,
    id,
    url: PUBLIC_BASE + '/' + filename,
    bytes: pdfBuf.length,
    statusCode: 200,
  },
}];

// Runs when HTTP Request to Gotenberg fails. Removes pending marker and
// returns error JSON for Respond node.

const fs = require('fs');

const MOP_DIR     = '/data/mop';
const PENDING_DIR = MOP_DIR + '/index/.pending';

const item = $input.first();
const j = item.json || {};

// Short-circuit path from Prepare (validation error) — just pass through
if (j._shortCircuit) {
  return [{ json: { ok: false, id: null, error: j.error, statusCode: j.statusCode || 400 } }];
}

const id = j.id || 'unknown';
try { fs.unlinkSync(PENDING_DIR + '/' + id); } catch (_) {}

// Gotenberg/HTTP error — item.json.error populated by onError:continueErrorOutput
const errMsg = (j.error && (j.error.message || j.error)) || 'gotenberg request failed';

return [{
  json: {
    ok: false,
    id,
    error: String(errMsg).slice(0, 500),
    statusCode: 500,
  },
}];
